double dot_product(const std::vector<double>& a, const std::vector<double>& b){
    size_t n = a.size();
    if (b.size() < n) n = b.size();
    double total = 0.0;
    for (size_t i = 0; i < n; ++i) total += a[i] * b[i];
    return total;
}

