enum Op { OP_ADD, OP_SUB, OP_MUL, OP_DIV };

double apply_op(Op op, double a, double b) {
    switch (op) {
        case OP_ADD: return a + b;
        case OP_SUB: return a - b;
        case OP_MUL: return a * b;
        case OP_DIV:
            if (b == 0.0) return 0.0;
            return a / b;
        default: return 0.0;
    }
}

